import{_ as e,c as s,o as t,ae as i}from"./chunks/framework.B7Y1jjX-.js";const P=JSON.parse('{"title":"8.1 排序基本概念","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/学习/408/数据结构/第八章 排序.md","filePath":"generated-notes/学习/408/数据结构/第八章 排序.md"}'),n={name:"generated-notes/学习/408/数据结构/第八章 排序.md"};function r(d,a,p,h,g,m){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="_8-1-排序基本概念" tabindex="-1">8.1 排序基本概念 <a class="header-anchor" href="#_8-1-排序基本概念" aria-label="Permalink to &quot;8.1 排序基本概念&quot;">​</a></h1><h3 id="稳定性" tabindex="-1">稳定性 <a class="header-anchor" href="#稳定性" aria-label="Permalink to &quot;稳定性&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251102185141.png">查看图片：Pasted image 20251102185141.png</a></p><h3 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to &quot;分类&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251102185109.png">查看图片：Pasted image 20251102185109.png</a></p><h1 id="_8-2-插入与希尔" tabindex="-1">8.2 插入与希尔 <a class="header-anchor" href="#_8-2-插入与希尔" aria-label="Permalink to &quot;8.2 插入与希尔&quot;">​</a></h1><h2 id="_8-2-1-插入排序" tabindex="-1">8.2.1 插入排序 <a class="header-anchor" href="#_8-2-1-插入排序" aria-label="Permalink to &quot;8.2.1 插入排序&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103143724.png">查看图片：Pasted image 20251103143724.png</a></p><h3 id="代码实现" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现" aria-label="Permalink to &quot;代码实现&quot;">​</a></h3><p>每次将大于待插入元素的前面的元素后移一位，再将待插入元素移入空出的位置： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103144227.png">查看图片：Pasted image 20251103144227.png</a> 空间复杂度：O(1)，时间复杂度：O(n^2)，稳定。在待排序的记录基本有序的时候，时间复杂度能达到O(1)的级别。</p><h3 id="优化" tabindex="-1">优化 <a class="header-anchor" href="#优化" aria-label="Permalink to &quot;优化&quot;">​</a></h3><p>在待插入元素的前面的部分是有序的，可以使用折半查找优化： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145002.png">查看图片：Pasted image 20251103145002.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145042.png">查看图片：Pasted image 20251103145042.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145127.png">查看图片：Pasted image 20251103145127.png</a> 此时low在high的右侧，停止折半查找，high右侧的元素均大于i所指元素，low左侧则均小于。在low和high中间的位置就是待插入元素的插入位置： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145257.png">查看图片：Pasted image 20251103145257.png</a> 特殊的，在这种情况下，不应该停止查找，而应该是在右侧继续寻找60，确保算法的稳定性： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145651.png">查看图片：Pasted image 20251103145651.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145812.png">查看图片：Pasted image 20251103145812.png</a> 这时，插入60就能够保证算法的稳定性： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103145845.png">查看图片：Pasted image 20251103145845.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103150256.png">查看图片：Pasted image 20251103150256.png</a></p><h2 id="_8-2-2-希尔排序" tabindex="-1">8.2.2 希尔排序 <a class="header-anchor" href="#_8-2-2-希尔排序" aria-label="Permalink to &quot;8.2.2 希尔排序&quot;">​</a></h2><p>将表中的元素拆分为多个子表，将子表中的元素排序，最后整体有序。</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151307.png">查看图片：Pasted image 20251103151307.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151347.png">查看图片：Pasted image 20251103151347.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151522.png">查看图片：Pasted image 20251103151522.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151545.png">查看图片：Pasted image 20251103151545.png</a> 在这一次排序中，表中的数据就已经基本有序： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151630.png">查看图片：Pasted image 20251103151630.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103151712.png">查看图片：Pasted image 20251103151712.png</a></p><h3 id="代码实现-1" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现-1" aria-label="Permalink to &quot;代码实现&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103152435.png">查看图片：Pasted image 20251103152435.png</a> 空间复杂度：O(1)，时间复杂度：在O(n^1.3)到O(n^2)，暂时无法用数学形式证明。不稳定。并且只能基于线性表实现。</p><h1 id="_8-3-交换排序" tabindex="-1">8.3 交换排序 <a class="header-anchor" href="#_8-3-交换排序" aria-label="Permalink to &quot;8.3 交换排序&quot;">​</a></h1><h2 id="_8-3-1-冒泡排序" tabindex="-1">8.3.1 冒泡排序 <a class="header-anchor" href="#_8-3-1-冒泡排序" aria-label="Permalink to &quot;8.3.1 冒泡排序&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103153829.png">查看图片：Pasted image 20251103153829.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103153859.png">查看图片：Pasted image 20251103153859.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103153950.png">查看图片：Pasted image 20251103153950.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103154029.png">查看图片：Pasted image 20251103154029.png</a></p><h3 id="算法实现" tabindex="-1">算法实现 <a class="header-anchor" href="#算法实现" aria-label="Permalink to &quot;算法实现&quot;">​</a></h3><p>若某一趟排序过程没有交换，就说明已经有序，可以提前结束： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103154257.png">查看图片：Pasted image 20251103154257.png</a></p><p>空间复杂度：O(1)，时间复杂度：O(n^2)，稳定。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103154658.png">查看图片：Pasted image 20251103154658.png</a></p><h2 id="_8-3-1-快速排序" tabindex="-1">8.3.1 快速排序 <a class="header-anchor" href="#_8-3-1-快速排序" aria-label="Permalink to &quot;8.3.1 快速排序&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160249.png">查看图片：Pasted image 20251103160249.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160517.png">查看图片：Pasted image 20251103160517.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160538.png">查看图片：Pasted image 20251103160538.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160556.png">查看图片：Pasted image 20251103160556.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160609.png">查看图片：Pasted image 20251103160609.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160626.png">查看图片：Pasted image 20251103160626.png</a> 将基准元素左右两侧的子表继续快排，直到左右子表就剩一个元素的时候</p><h3 id="代码实现-重点" tabindex="-1">代码实现（重点） <a class="header-anchor" href="#代码实现-重点" aria-label="Permalink to &quot;代码实现（重点）&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103160903.png">查看图片：Pasted image 20251103160903.png</a></p><p>空间复杂度：O(递归层数)，时间复杂度：O(n * 递归层数)，不稳定。递归层数的数量级在log n与n之间。理想情况下，空间复杂度：O(log n)，时间复杂度：O(nlog n) <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103163056.png">查看图片：Pasted image 20251103163056.png</a></p><p>对于本有序的序列，快排的性能最差。可以随机选取枢轴元素来解决这个问题。</p><h1 id="_8-4-选择排序" tabindex="-1">8.4 选择排序 <a class="header-anchor" href="#_8-4-选择排序" aria-label="Permalink to &quot;8.4 选择排序&quot;">​</a></h1><h2 id="_8-4-1-简单选择排序-暴力" tabindex="-1">8.4.1 简单选择排序（暴力） <a class="header-anchor" href="#_8-4-1-简单选择排序-暴力" aria-label="Permalink to &quot;8.4.1 简单选择排序（暴力）&quot;">​</a></h2><p>在待排序的元素中选着最小的加入有序队列</p><h3 id="代码实现-2" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现-2" aria-label="Permalink to &quot;代码实现&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103163815.png">查看图片：Pasted image 20251103163815.png</a> 空间复杂度：O(1)，时间复杂度：O(n^2)，不稳定。</p><h2 id="_8-4-2-堆排序" tabindex="-1">8.4.2 堆排序 <a class="header-anchor" href="#_8-4-2-堆排序" aria-label="Permalink to &quot;8.4.2 堆排序&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103171311.png">查看图片：Pasted image 20251103171311.png</a> 被选出的堆顶元素，就不会再继续参与排序（已确定）</p><h3 id="代码实现-3" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现-3" aria-label="Permalink to &quot;代码实现&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103171801.png">查看图片：Pasted image 20251103171801.png</a> 建堆过程时间复杂度：O(n)，排序整体时间复杂度：O(nlog n)，空间复杂度：O(1)，不稳定</p><h3 id="堆" tabindex="-1">堆 <a class="header-anchor" href="#堆" aria-label="Permalink to &quot;堆&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103165446.png">查看图片：Pasted image 20251103165446.png</a> 逻辑上是一棵顺序存储的完全二叉树，大根堆就是根节点大于左右子树。</p><p>将初始的序列建立为一个大根堆，再使用选择排序就能提高效率。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103170150.png">查看图片：Pasted image 20251103170150.png</a></p><h3 id="堆的代码实现" tabindex="-1">堆的代码实现 <a class="header-anchor" href="#堆的代码实现" aria-label="Permalink to &quot;堆的代码实现&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103170622.png">查看图片：Pasted image 20251103170622.png</a></p><h3 id="堆插入与删除" tabindex="-1">堆插入与删除 <a class="header-anchor" href="#堆插入与删除" aria-label="Permalink to &quot;堆插入与删除&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103173416.png">查看图片：Pasted image 20251103173416.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103173627.png">查看图片：Pasted image 20251103173627.png</a></p><h1 id="_8-5" tabindex="-1">8.5 <a class="header-anchor" href="#_8-5" aria-label="Permalink to &quot;8.5&quot;">​</a></h1><h2 id="_8-5-1-归并排序" tabindex="-1">8.5.1 归并排序 <a class="header-anchor" href="#_8-5-1-归并排序" aria-label="Permalink to &quot;8.5.1 归并排序&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103191125.png">查看图片：Pasted image 20251103191125.png</a></p><h3 id="代码实现-4" tabindex="-1">代码实现 <a class="header-anchor" href="#代码实现-4" aria-label="Permalink to &quot;代码实现&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103191743.png">查看图片：Pasted image 20251103191743.png</a></p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103192432.png">查看图片：Pasted image 20251103192432.png</a> 时间复杂度：O(nlog n)，空间复杂度：O(n)（其中包括辅助数组n和递归栈所占用的空间log n），稳定的。</p><h3 id="归并" tabindex="-1">归并 <a class="header-anchor" href="#归并" aria-label="Permalink to &quot;归并&quot;">​</a></h3><p>将多个有序的序列合并 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103190045.png">查看图片：Pasted image 20251103190045.png</a></p><p>考试通常是二路，手算。上例是二路归并，下面为四路： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103190716.png">查看图片：Pasted image 20251103190716.png</a></p><h2 id="_8-5-2-基数排序" tabindex="-1">8.5.2 基数排序 <a class="header-anchor" href="#_8-5-2-基数排序" aria-label="Permalink to &quot;8.5.2 基数排序&quot;">​</a></h2><p>将关键字的每个位数取出排序后，再取高位再排序，直到全部的位都被排序过 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103193727.png">查看图片：Pasted image 20251103193727.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103193651.png">查看图片：Pasted image 20251103193651.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103193916.png">查看图片：Pasted image 20251103193916.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103194045.png">查看图片：Pasted image 20251103194045.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103194202.png">查看图片：Pasted image 20251103194202.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103194249.png">查看图片：Pasted image 20251103194249.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103194333.png">查看图片：Pasted image 20251103194333.png</a> 通常基于链式存储实现，空间复杂度：O(每位可能取值的个数)，时间复杂度：O(分配的次数 * (关键字的位数 + 每位可能取值的个数))，稳定的。</p><p>对于要排序的数据可以拆分、分组不太多的时候时候使用： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251103195835.png">查看图片：Pasted image 20251103195835.png</a></p><h2 id="_8-5-3-计数排序" tabindex="-1">8.5.3 计数排序 <a class="header-anchor" href="#_8-5-3-计数排序" aria-label="Permalink to &quot;8.5.3 计数排序&quot;">​</a></h2><h1 id="_8-7-外部排序" tabindex="-1">8.7 外部排序 <a class="header-anchor" href="#_8-7-外部排序" aria-label="Permalink to &quot;8.7 外部排序&quot;">​</a></h1><h2 id="_8-7-1-基础概念" tabindex="-1">8.7.1 基础概念 <a class="header-anchor" href="#_8-7-1-基础概念" aria-label="Permalink to &quot;8.7.1 基础概念&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108153246.png">查看图片：Pasted image 20251108153246.png</a></p><h3 id="构造初始归并段" tabindex="-1">构造初始归并段 <a class="header-anchor" href="#构造初始归并段" aria-label="Permalink to &quot;构造初始归并段&quot;">​</a></h3><p>将第一块与第二块的内容读入内存，进行内部排序，再写入内存变为一个归并段： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108153650.png">查看图片：Pasted image 20251108153650.png</a></p><h3 id="第一趟归并" tabindex="-1">第一趟归并 <a class="header-anchor" href="#第一趟归并" aria-label="Permalink to &quot;第一趟归并&quot;">​</a></h3><p>将归并段进行归并： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108153909.png">查看图片：Pasted image 20251108153909.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108154021.png">查看图片：Pasted image 20251108154021.png</a></p><h3 id="第二趟归并" tabindex="-1">第二趟归并 <a class="header-anchor" href="#第二趟归并" aria-label="Permalink to &quot;第二趟归并&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108154156.png">查看图片：Pasted image 20251108154156.png</a></p><h3 id="时间开销分析" tabindex="-1">时间开销分析 <a class="header-anchor" href="#时间开销分析" aria-label="Permalink to &quot;时间开销分析&quot;">​</a></h3><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108154418.png">查看图片：Pasted image 20251108154418.png</a> 时间开销=读写时间+排序时间（构造初始归并段）+归并时间</p><p>减少归并的次数就能减少读写的时间： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108155045.png">查看图片：Pasted image 20251108155045.png</a></p><h2 id="_8-7-2-败者树" tabindex="-1">8.7.2 败者树 <a class="header-anchor" href="#_8-7-2-败者树" aria-label="Permalink to &quot;8.7.2 败者树&quot;">​</a></h2><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108155324.png">查看图片：Pasted image 20251108155324.png</a> 使用多路归并时，对比的次数会变多，可以使用败者树优化</p><p><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108160637.png">查看图片：Pasted image 20251108160637.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108160729.png">查看图片：Pasted image 20251108160729.png</a> 初始构造时对比k-1次，之后使用败者树最少可以对比log k向上取整的次数，比k-1要少的多</p><h2 id="_8-7-3-置换-选择排序" tabindex="-1">8.7.3 置换-选择排序 <a class="header-anchor" href="#_8-7-3-置换-选择排序" aria-label="Permalink to &quot;8.7.3 置换-选择排序&quot;">​</a></h2><p>优化构造初始归并段的过程，来构建更长的初始归并段： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108162054.png">查看图片：Pasted image 20251108162054.png</a></p><p>将比minmax更大的最小值输出，直到wa中不能再输出，就生成一个新的归并段： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108162221.png">查看图片：Pasted image 20251108162221.png</a></p><h2 id="_8-7-4-最佳归并树" tabindex="-1">8.7.4 最佳归并树 <a class="header-anchor" href="#_8-7-4-最佳归并树" aria-label="Permalink to &quot;8.7.4 最佳归并树&quot;">​</a></h2><p>使用置换-选择排序算法生成的归并段长度不一，每次都要读写每个段的长度： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108162604.png">查看图片：Pasted image 20251108162604.png</a></p><p>使用哈夫曼树来得到wpl最小的树： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108162745.png">查看图片：Pasted image 20251108162745.png</a></p><p>构造3路归并的最佳归并树： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108162951.png">查看图片：Pasted image 20251108162951.png</a></p><p>如果无法构造k叉归并树： <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108163232.png">查看图片：Pasted image 20251108163232.png</a><a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020251108163732.png">查看图片：Pasted image 20251108163732.png</a></p>',81)])])}const l=e(n,[["render",r]]);export{P as __pageData,l as default};
